let rawText = $input.first().json.output || $input.first().json.text || "";
let parsed = {};

try {
  let jsonMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[1]);
  } else {
    parsed = JSON.parse(rawText);
  }
} catch (e) {
  parsed = {
    intent: "general_query",
    extracted_entities: {},
    summary: rawText
  };
}

return {
  json: {
    status: "success",
    intent: parsed.intent || "general_query",
    extracted_entities: parsed.extracted_entities || {},
    summary: parsed.summary || rawText,
    raw_response: rawText
  }
};
